Expr*
Ast2Asg::operator()(ast::EqualityExpressionContext* ctx)
{
  auto list = ctx->relationalExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->children[i * 2 - 1])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::EqualEqual: node->op = node->kEq; break;
      case ast::NotEqual: node->op = node->kNe; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::RelationalExpressionContext* ctx)
{
  auto list = ctx->shiftExpression();
  Expr* ret = self(list[0]);
  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->children[i * 2 - 1])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::Less: node->op = node->kLt; break;
      case ast::Greater: node->op = node->kGt; break;
      case ast::LessEqual: node->op = node->kLe; break;
      case ast::GreaterEqual: node->op = node->kGe; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::ShiftExpressionContext* ctx)
{
  return self(ctx->additiveExpression());
}

Expr*
Ast2Asg::operator()(ast::AdditiveExpressionContext* ctx)
{
  auto list = ctx->mul();
  Expr* ret = self(list[0]);

  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->children[i * 2 - 1])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::Plus: node->op = node->kAdd; break;
      case ast::Minus: node->op = node->kSub; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(list[i]);
    ret = node;
  }

  return ret;
}

Expr*
Ast2Asg::operator()(ast::MultiplicativeExpressionContext* ctx)
{
  auto list = ctx->unaryExpression();
  Expr* ret = self(list[0]);

  for (unsigned i = 1; i < list.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(ctx->children[i * 2 - 1])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::Star: node->op = node->kMul; break;
      case ast::Slash: node->op = node->kDiv; break;
      case ast::Percent: node->op = node->kMod; break;
      default: ABORT();
    }
    node->lft = ret;
    node->rht = self(list[i]);
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::CastExpressionContext* ctx)
{
  return self(ctx->unaryExpression());
}

Expr*
Ast2Asg::operator()(ast::UnaryExpressionContext* ctx)
{
  if (auto ret = make<UnaryExpr>();
  if (auto op = ctx->unaryOperator()) {
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(op->children[0])
                   ->getSymbol()->getType();
    switch (token) {
      case ast::Plus: ret->op = ret->kPos; break;
      case ast::Minus: ret->op = ret->kNeg; break;
      case ast::Not: ret->op = ret->kNot; break;
      default: break;
    }
    ret->sub = self(ctx->unaryExpression());
    return ret;
  }

  return self(ctx->postfixExpression());
}

Expr*
Ast2Asg::operator()(ast::PostfixExpressionContext* ctx)
{
  auto sub = self(ctx->primaryExpression());
  auto children = ctx->children;
  for (unsigned i = 1; i < children.size(); ++i) {
    auto child = children[i];
    if (auto tn = dynamic_cast<antlr4::tree::TerminalNode*>(child)) {
      if (tn->getSymbol()->getType() == ast::LeftParen) {
        auto call = make<CallExpr>();
        call->head = sub;
        i++;
        while (i < children.size()) {
          if (auto argCtx = dynamic_cast<ast::ArgumentExpressionListContext*>(children[i])) {
            for (auto&& expr : argCtx->assignmentExpression())
              call->args.push_back(self(expr));
            i++;
          } else
            break;
        }
        sub = call;
      } else if (tn->getSymbol()->getType() == ast::LeftBracket) {
        auto index = make<BinaryExpr>();
        index->op = index->kIndex;
        index->lft = sub;
        i++;
        if (i < children.size())
          index->rht = self(dynamic_cast<ast::ExpressionContext*>(children[i]));
        i++;
        sub = index;
      }
    }
  }
  return sub;
}

Expr*
Ast2Asg::operator()(ast::PrimaryExpressionContext* ctx)
{
  if (auto p = ctx->Identifier()) {
    auto name = p->getText();
    auto ret = make<DeclRefExpr>();
    ret->decl = mSymtbl->resolve(name);
    return ret;
  }

  if (auto p = ctx->Constant()) {
    auto text = p->getText();
    auto ret = make<IntegerLiteral>();
    ASSERT(!text.empty());
    if (text[0] != '0')
      ret->val = std::stoll(text);
    else if (text.size() == else if (text[1] == 'x' || text[1] == 'X')
      ret->val = std::stoll(text.substr(2), nullptr, 16);
    else
      ret->val = std::stoll(text.substr(1), nullptr, 8);
    return ret;
  }

  if (auto p = ctx->expression()) {
    auto ret = make<ParenExpr>();
    ret->sub = self(p);
    return ret;
  }

  ABORT();
}

Expr*
Ast2Asg::operator()(ast::InitializerContext* ctx)
{
  if (auto p = ctx->assignmentExpression())
    return self(p);

  auto ret = make<InitListExpr>();
  if (auto p = ctx->initializerList()) {
    for (auto&& i : p->initializer()) {
      auto expr = self(i);
      if (auto p = expr->dcst<InitListExpr>()) {
        for (auto&& sub : p->list)
          ret->list.push_back(sub);
      } else {
        ret->list.push_back(expr);
      }
    }
  }
  return ret;
}

//==============================================================================
// 语句
//==============================================================================

Stmt*
Ast2Asg::operator()(ast::StatementContext* ctx)
{
  if (auto p = ctx->compoundStatement())
    return self(p);

  if (auto p = ctx->expressionStatement())
    return self(p);

  if (auto p = ctx->jumpStatement())
    return self(p);

  if (auto p = ctx->selectionStatement())
    return self(p);

  if (auto p = ctx->iterationStatement())
    return self(p);

  if (auto p = ctx->labeledStatement())
    return self(p->statement());

  ABORT();
}

CompoundStmt*
Ast2Asg::operator()(ast::CompoundStatementContext* ctx)
{
  auto ret = make<CompoundStmt>();

  if (auto p = ctx->blockItemList()) {
    Symtbl localDecls(self);

    for (auto&& i : p->blockItem()) {
      if (auto q = i->declaration()) {
        auto sub = make<DeclStmt>();
        sub->decls = self(q);
        ret->subs.push_back(sub);
      }

      else if (auto q = i->statement())
        ret->subs.push_back(self(q));

      else
        ABORT();
    }
  }

  return ret;
}

Stmt*
Ast2Asg::operator()(ast::ExpressionStatementContext* ctx)
{
  if (auto p = ctx->expression()) {
    auto ret = make<ExprStmt>();
    ret->expr = self(p);
    return ret;
  }

  return make<NullStmt>();
}

Stmt*
Ast2Asg::operator()(ast::JumpStatementContext* ctx)
{
  if (ctx->Return()) {
    auto ret = make<ReturnStmt>();
    ret->func = mCurrentFunc;
    if (auto p = ctx->expression())
      ret->expr = self(p);
    return ret;
  }

  if (ctx->Break()) {
    return make<BreakStmt>();
  }

  if (ctx->Continue()) {
    return make<ContinueStmt>();
  }

  ABORT();
}

Stmt*
Ast2Asg::operator()(ast::SelectionStatementContext* ctx)
{
  auto ret = make<IfStmt>();
  ret->cond = self(ctx->expression());
  ret->then = self(ctx->statement(0));
  if (ctx->Else())
    ret->else_ = self(ctx->statement(1));
  return ret;
}

Stmt*
Ast2Asg::operator()(ast::IterationStatementContext* ctx)
{
  if (ctx->While()) {
    auto ret = make<WhileStmt>();
    ret->cond = self(ctx->expression());
    ret->body = self(ctx->statement());
    return ret;
  }

  if (ctx->Do()) {
    auto ret = make<DoStmt>();
    ret->body = self(ctx->statement());
    ret->cond = self(
      dynamic_cast<ast::ExpressionContext*>(
        ctx->children[ctx->children.size() - 2]));
    return ret;
  }

  ABORT();
}

//==============================================================================
// 声明
//==============================================================================

std::vector<Decl*>
Ast2Asg::operator()(ast::DeclarationContext* ctx)
{
  std::vector<Decl*> ret;

  auto specs = self(ctx->declarationSpecifiers());

  if (auto p = ctx->initDeclaratorList()) {
    for (auto&& j : p->initDeclarator())
      ret.push_back(self(j, specs));
  }

  return ret;
}

FunctionDecl*
Ast2Asg::operator()(ast::FunctionDefinitionContext* ctx)
{
  auto ret = make<FunctionDecl>();
  mCurrentFunc = ret;

  auto type = make<Type>();
  ret->type = type;

  auto sq = self(ctx->declarationSpecifiers());
  type->spec = sq.first, type->qual = sq.second;

  auto [texp, name] = self(ctx->declarator(), nullptr);
  auto funcType = make<FunctionType>();
  funcType->sub = texp;
  type->texp = funcType;
  ret->name = std::move(name);

  Symtbl localDecls(self);

  (*mSymtbl)[ret->name] = ret;

  ret->body = self(ctx->compoundStatement());

  return ret;
}

Decl*
Ast2Asg::operator()(ast::InitDeclaratorContext* ctx, SpecQual sq)
{
  auto [texp, name] = self(ctx->declarator(), nullptr);
  Decl* ret;

  if (texp->dcst<FunctionType>()) {
    auto fdecl = make<FunctionDecl>();
    auto type = make<Type>();
    fdecl->type = type;

    type->spec = sq.first;
    type->qual = sq.second;
    type->texp = texp;

    fdecl->name = std::move(name);
    for (auto p : texp->dcst<FunctionType>()->params) {
      auto paramDecl = make<VarDecl>();
      paramDecl->type = p;
      fdecl->params.push_back(paramDecl);
    }

    if (ctx->initializer())
      ABORT();
    fdecl->body = nullptr;

    ret = fdecl;
  }

  else {
    auto vdecl = make<VarDecl>();
    auto type = make<Type>();
    vdecl->type = type;

    type->spec = sq.first;
    type->qual = sq.second;
    type->texp = texp;
    vdecl->name = std::move(name);

    if (auto p = ctx->initializer())
      vdecl->init = self(p);
    else
      vdecl->init = nullptr;

    ret = vdecl;
  }

  (*mSymtbl)[ret->name] = ret;
  return ret;
}

